from pydantic import BaseModel, Field
from enum import Enum

class UserRole(str, Enum):
    ADMIN = 'admin'
    USER = 'user'

class AuthenticatedResponse(BaseModel):
    user_id: int
    role: UserRole = Field(..., description='Required role')
    resource_access: dict

    @validator('resource_access')
    def check_permissions(cls, v, values):
        role = values.get('role')
        if role == UserRole.USER and 'admin' in v:
            raise ValueError('INSUFFICIENT_PERMISSIONS: User lacks admin access')
        return v

# Usage in agent result validator
@result_validator(model=AuthenticatedResponse)
def monitor_permissions(result):
    print(f'✅ Permissions OK for {result.role}: {result.resource_access.keys()}')
    return result

