from pydantic_ai import Agent, tool, result_validator
import jwt
from datetime import datetime

class AuthMiddleware:
    def __init__(self, refresh_token: str):
        self.refresh_token = refresh_token

    def refresh_access_token(self, token: str) -> str:
        # Simulate token refresh
        if 'expired' in token:
            return f'Bearer {jwt.encode({"exp": datetime.utcnow().timestamp() + 3600}, "secret")}'
        return token

# Apply to agent
agent = Agent()

@result_validator
async def auto_refresh_auth(result):
    if hasattr(result, 'headers') and 'Authorization' in result.headers:
        token = result.headers['Authorization']
        refreshed = AuthMiddleware('refresh_token').refresh_access_token(token)
        if refreshed != token:
            result.headers['Authorization'] = refreshed
            print('🔄 Token refreshed automatically')
    return result

agent.add_result_validator(auto_refresh_auth)

from contextvars import ContextVar, copy_context
from pydantic_ai import Agent, tool

# Thread-local auth context
current_auth = ContextVar('current_auth', default=None)

class AuthContext:
    def __init__(self, user_id: str, token: str):
        self.user_id = user_id
        self.token = token

@tool
def secure_tool_call(*args, **kwargs):
    auth = current_auth.get()
    if not auth:
        raise ValueError('No auth context')
    print(f'Executing with auth: {auth.user_id}')
    return 'success'

# Context manager for agent execution
async def with_auth_context(agent: Agent, user_id: str, token: str):
    ctx = copy_context()
    ctx.run(current_auth.set, AuthContext(user_id, token))
    return await agent.run('Secure operation', context=ctx)

from pydantic import BaseModel
from typing import List, Optional, Literal
from pydantic_ai import Agent

class CapabilityResponse(BaseModel):
    granted: List[str]
    denied: List[str]
    fallback: Optional[str] = None

PERMISSION_FALLBACKS = {
    'admin_panel': 'user_dashboard',
    'delete_user': 'view_user',
    'edit_all': 'edit_own'
}

@result_validator(model=CapabilityResponse)
def handle_permission_denials(result: CapabilityResponse):
    for denied in result.denied:
        if denied in PERMISSION_FALLBACKS:
            result.fallback = PERMISSION_FALLBACKS[denied]
            print(f'🔄 Fallback: {denied} → {result.fallback}')
    return result

# Agent automatically handles fallbacks
agent = Agent(result_validators=[handle_permission_denials])
